import os
from typing import List, Dict
from lightllm.server.core.objs import Req
from lightllm.utils.log_utils import init_logger

logger = init_logger(__name__)


LIGHTLLM_DECODE_PREFIX_LENGTH = int(os.getenv("LIGHTLLM_DECODE_PREFIX_LENGTH", 5))


class DecodeReq:
    def __init__(
        self,
        req: Req,
        is_pd_decode_mode: bool,
    ) -> None:
        self.request_id = req.request_id
        self.group_req_id = req.group_req_id
        self.prompt_ids = req.shm_prompt_ids.arr[0 : req.input_len].tolist()
        self.output_ids = []
        self.output_strs = []
        self.prefix_offset = max(len(self.prompt_ids) - LIGHTLLM_DECODE_PREFIX_LENGTH, 0)

        if is_pd_decode_mode:
            # pd decode mode 需要模拟一下 prefill 输出的第一个token
            self.read_offset = max(0, len(self.prompt_ids) - 1)
        else:
            self.read_offset = len(self.prompt_ids)

        self.req = req
        self.input_len = self.req.input_len
        self.prefix_str = ""
        self.stop_strs: List[str] = self.req.sample_params.stop_sequences.to_strings()
        # to_strings()已经做了倒序排列，第一个元素就是最长字符串
        self.stop_str_max_len = len(self.stop_strs[0]) if self.stop_strs else 0

    def init_token_healing_prefix_str(self, token_id_to_token: Dict[int, str], tokenizer):
        tokens = [token_id_to_token[token_id] for token_id in self.req.prefix_token_ids.get_token_ids()]
        if tokens:
            self.prefix_str = tokenizer.convert_tokens_to_string(tokens)
        else:
            self.prefix_str = ""
        return

    def stop_sequences_str_match(self) -> bool:
        stop_strs = self.stop_strs
        if not stop_strs or self.stop_str_max_len == 0:
            return False

        tail_token_len = self.stop_str_max_len + 10  # 10 for safety
        tail_token_strs = self.output_strs[-tail_token_len:]
        tail_str = "".join(tail_token_strs)

        for stop_str in stop_strs:
            if stop_str in tail_str:
                logger.debug(
                    f"req_id {self.request_id} Found stop sequence in tail: stop_str='{stop_str}', "
                    f"tail_str='{tail_str}'"
                )
                return True
        return False

    def need_detoken(self):
        if (
            (not self.req.is_aborted)
            and (not self.req.stop_str_matched)
            and len(self.output_ids) < self.req.candetoken_out_len
        ):
            return True
        return False

    def out_queue_is_full(self):
        return self.req.out_tokens_queue.is_full()

    def get_next_token_id_and_index(self):
        src_index = self.input_len + len(self.output_ids)
        return self.req.shm_prompt_ids.arr[src_index], src_index

    def get_decode_tokens(self):
        prefix_tokens = self.req.shm_prompt_ids.arr[self.prefix_offset : self.read_offset].tolist()
        read_tokens = self.req.shm_prompt_ids.arr[self.prefix_offset : self.input_len + len(self.output_ids)].tolist()
        return prefix_tokens, read_tokens

    def can_set_release_mark(self):
        if self.req.is_aborted:
            return True
        if self.req.stop_str_matched:
            return True
        if (
            self.req.finish_status.is_finished()
            and self.req.candetoken_out_len == len(self.output_ids)
            and self.req.finish_token_index == self.input_len + len(self.output_ids) - 1
        ):
            return True
        return False

    async def handle_loop(self):
        self.recycle_event = asyncio.Event()
        asyncio.create_task(self.recycle_resource_loop())

        # 多节点tp模式下的slave节点，需要开启一个协程task用来接收
        # master 转发过来的请求对象。
        if self.is_multinode_tp_slave:
            asyncio.create_task(self.loop_for_request())

        if self.pd_mode.is_P_or_D():
            from lightllm.server.httpserver.pd_loop import pd_handle_loop

            asyncio.create_task(pd_handle_loop(self))

        while True:
            try:
                await asyncio.wait_for(self.zmq_recv_socket.recv_pyobj(), timeout=0.05)
            except asyncio.TimeoutError:
                pass

            try:
                for group_req_id_ in list(self.req_id_to_out_inf.keys()):
                    req_status = self.req_id_to_out_inf.get(group_req_id_, None)
                    if req_status is None:
                        continue

                    token_list = []
                    for req in req_status.group_req_objs.shm_req_objs:
                        req_id = req.request_id
                        read_token_count = 1
                        if req.out_tokens_queue.is_full():
                            read_token_count = LIGHTLLM_OUT_TOKEN_QUEUE_SIZE

                        for _ in range(read_token_count):
                            if not req.out_tokens_queue.is_empty():

                                text, src_index, special, count_output_tokens = req.out_tokens_queue.peek()
                                req.cumlogprob += float(req.shm_logprobs.arr[src_index])
                                metadata = {
                                    "id": int(req.shm_prompt_ids.arr[src_index]),
                                    "logprob": float(req.shm_logprobs.arr[src_index]),
                                    "cumlogprob": float(req.cumlogprob) / count_output_tokens,
                                    "special": special,
                                    "count_output_tokens": count_output_tokens,
                                    "prompt_cache_len": req.prompt_cache_len,
                                    "cpu_prompt_cache_len": req.cpu_prompt_cache_len,
                                    "disk_prompt_cache_len": req.disk_prompt_cache_len,
                                    "mtp_accepted_token_num": req.mtp_accepted_token_num,
                                }
                                if self.args.return_all_prompt_logprobs:
                                    metadata.update(req.get_all_prompt_metadata())
                                if self.args.use_reward_model:
                                    metadata["score"] = float(req.reward_score)

                                req.out_tokens_queue.pop_no_ret()

                                finished_token_index = (
                                    req.stop_str_matched_token_index if req.stop_str_matched else req.finish_token_index
                                )

                                if finished_token_index != src_index:
                                    token_list.append((req_id, text, metadata, FinishStatus()))
                                else:
                                    if req.stop_str_matched:
                                        finish_status = FinishStatus(FinishStatus.FINISHED_STOP)
                                    else:
                                        finish_status = FinishStatus(req.finish_status.status)

                                    token_list.append((req_id, text, metadata, finish_status))
                            else:
                                break

                    async with req_status.lock:
                        req_status.out_token_info_list.extend(token_list)
                        req_status.event.set()
            except BaseException as e:
                logger.exception(str(e))
                raise e

            self.recycle_event.set()
        return


class ReqStatus:
    def __init__(self, group_request_id, multimodal_params, req_objs: List[Req], start_time) -> None:
        self.lock = asyncio.Lock()
        self.event = asyncio.Event()
        self.group_req_objs = GroupReqObjs(
            group_req_id=group_request_id,
            multimodal_params=multimodal_params,
            shm_req_objs=req_objs,
            time_mark=start_time,
        )
        self.out_token_info_list = []
        self.aborted = False

    def can_release(self):
        for req in self.group_req_objs.shm_req_objs:
            if not req.can_release():
                return False

from dataclasses import dataclass
from lightllm.server.multimodal_params import MultimodalParams
from typing import List
from ..req import Req


@dataclass
class GroupReqIndexes:
    group_req_id: int
    multimodal_params: MultimodalParams
    shm_req_indexes: List[int]
    time_mark: float


@dataclass
class GroupReqObjs:
    group_req_id: int
    multimodal_params: MultimodalParams
    shm_req_objs: List[Req]
    time_mark: float

    def to_group_req_index(self):
        return GroupReqIndexes(
            group_req_id=self.group_req_id,
            multimodal_params=self.multimodal_params,
            shm_req_indexes=[req.index_in_shm_mem for req in self.shm_req_objs],
            time_mark=self.time_mark,
        )


@dataclass
class AbortedReqCmd:
    req_id: int


@dataclass
class StopStrMatchedReqCmd:
    req_id: int
